1	use serde::{Deserialize, Serialize};
2	use std::fs;
3	use std::io;
4	use std::path::PathBuf;
5	
6	const MAX_CONFIG_SIZE: u64 = 1_048_576; // 1 MB
7	
8	#[derive(Serialize, Deserialize, Clone, Debug)]
9	#[serde(default)]
10	pub struct Config {
11	    pub font_size: f32,
12	    pub mono_font_size: f32,
13	    pub ui_scale: f32,
14	    pub dark_mode: bool,
15	    pub default_endpoint: String,
16	    pub system_prompt: String,
17	    pub temperature: f32,
18	    pub max_tokens: u32,
19	    pub use_max_tokens: bool,
20	    pub saved_endpoints: Vec<String>,
21	    pub font_family: String,
22	    pub mono_font_family: String,
23	}
24	
25	impl Default for Config {
26	    fn default() -> Self {
27	        Self {
28	            font_size: 14.0,
29	            mono_font_size: 13.0,
30	            ui_scale: 1.0,
31	            dark_mode: true,
32	            default_endpoint: "http://localhost:11434/v1".to_string(),
33	            system_prompt: String::new(),
34	            temperature: 0.7,
35	            max_tokens: 2048,
36	            use_max_tokens: false,
37	            saved_endpoints: vec!["http://localhost:11434/v1".to_string()],
38	            font_family: String::new(),
39	            mono_font_family: String::new(),
40	        }
41	    }
42	}
43	
44	impl Config {
45	    pub fn path() -> Result<PathBuf, String> {
46	        dirs::home_dir()
47	            .map(|h| h.join(".config/hchat/config.toml"))
48	            .ok_or_else(|| "Could not determine home directory".to_string())
49	    }
50	
51	    pub fn load() -> Self {
52	        let path = match Self::path() {
53	            Ok(p) => p,
54	            Err(e) => {
55	                eprintln!("Warning: {e}, using default config");
56	                return Self::default();
57	            }
58	        };
59	
60	        match fs::metadata(&path) {
61	            Ok(meta) => {
62	                if meta.len() > MAX_CONFIG_SIZE {
63	                    eprintln!(
64	                        "Warning: config file too large ({} bytes), using defaults",
65	                        meta.len()
66	                    );
67	                    return Self::default();
68	                }
69	            }
70	            Err(e) if e.kind() == io::ErrorKind::NotFound => {
71	                let config = Self::default();
72	                if let Err(e) = config.save() {
73	                    eprintln!("Warning: could not save default config: {e}");
74	                }
75	                return config;
76	            }
77	            Err(e) => {
78	                eprintln!("Warning: could not read config file: {e}");
79	                return Self::default();
80	            }
81	        }
82	
83	        match fs::read_to_string(&path) {
84	            Ok(contents) => {
85	                let mut config: Config = toml::from_str(&contents).unwrap_or_else(|e| {
86	                    eprintln!("Warning: could not parse config: {e}, using defaults");
87	                    Self::default()
88	                });
89	                config.sanitize();
90	                config
91	            }
92	            Err(e) => {
93	                eprintln!("Warning: could not read config file: {e}");
94	                Self::default()
95	            }
96	        }
97	    }
98	
99	    pub fn save(&self) -> Result<(), String> {
100	        let path = Self::path()?;
101	        if let Some(parent) = path.parent() {
102	            fs::create_dir_all(parent)
103	                .map_err(|e| format!("Could not create config directory: {e}"))?;
104	        }
105	        let contents =
106	            toml::to_string_pretty(self).map_err(|e| format!("Could not serialize config: {e}"))?;
107	        let tmp = path.with_extension("toml.tmp");
108	        fs::write(&tmp, &contents).map_err(|e| format!("Could not write config file: {e}"))?;
109	        fs::rename(&tmp, &path).map_err(|e| {
110	            let _ = fs::remove_file(&tmp);
111	            format!("Could not finalize config file: {e}")
112	        })?;
113	        Ok(())
114	    }
